<?php namespace App\Http\Middleware; use Closure; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Auth; class AuditLogMiddleware { public function handle(Request $request, Closure $next) { if ($this->isDataChangingRequest($request)) { $this->logAction($request); } return $next($request); } protected function isDataChangingRequest(Request $request): bool { return in_array($request->method(), ['POST', 'PUT', 'PATCH', 'DELETE']); } protected function logAction(Request $request): void { DB::table('audit_logs')->insert([ 'user_id' => Auth::id(), 'ip_address' => $request->ip(), 'url' => $request->fullUrl(), 'action' => $request->method(), 'payload' => json_encode($request->except(['password', 'password_confirmation'])), 'created_at' => now(), ]); } }